<template>
  <view class="setting-item" @click="handleClick">
    <text class="label">{{ label }}</text>
    <view class="right-content">
      <text v-if="badge" class="badge">{{ badge }}</text>
      <switch v-else-if="switchable" class="custom-switch" :checked="switchValue" @change="handleSwitchChange" />
      <text v-else class="arrow">＞</text>
    </view>
  </view>
</template>

<script>
export default {
  name: 'SettingItem',
  props: {
    label: {
      type: String,
      required: true
    },
    badge: {
      type: String,
      default: ''
    },
    switchable: {
      type: Boolean,
      default: false
    },
    switchValue: {
      type: Boolean,
      default: false
    }
  },
  methods: {
    handleClick() {
      if (!this.switchable) {
        this.$emit('click');
      }
    },
    handleSwitchChange(e) {
      this.$emit('update:switchValue', e.detail.value);
    }
  }
};
</script>

